def dfs(graph, s, t, visited, parent):
    visited[s] = True
    if s == t:
        return True
    for v, cap in enumerate(graph[s]):
        if not visited[v] and cap > 0:
            parent[v] = s
            if dfs(graph, v, t, visited, parent):
                return True
    return False

def ford_fulkerson(graph, source, sink):
    parent = [-1] * len(graph)
    max_flow = 0
    
    while True:
        visited = [False] * len(graph)
        if not dfs(graph, source, sink, visited, parent):
            break
            
        path_flow = float('inf')
        s = sink
        while s != source:
            path_flow = min(path_flow, graph[parent[s]][s])
            s = parent[s]
            
        max_flow += path_flow
        v = sink
        while v != source:
            u = parent[v]
            graph[u][v] -= path_flow
            graph[v][u] += path_flow
            v = parent[v]
            
    return max_flow

